// JWT fixtures for IotaService tests.
//
// Each constant is a dot-separated JWT whose payload matches the field
// descriptions below. The signature part is intentionally fake — the
// CryptographyService is mocked in tests so no real verification occurs.

/// A well-formed JWT with a valid payload and no `purpose` field.
const validJwt =
    'eyJhbGciOiJFUzI1NiIsInR5cCI6IkpXVCJ9'
    '.'
    '.fakesig';

/// A well-formed JWT whose `presentation_definition` contains a valid
/// `purpose` JSON string with `data_collection_purpose` and
/// `request_description` fields.
const validJwtWithPurpose =
    'eyJhbGciOiJFUzI1NiIsInR5cCI6IkpXVCJ9'
    '.'
    '.fakesig';

/// A JWT whose `response_mode` is `query` instead of `direct_post`.
const jwtWithWrongResponseMode =
    'eyJhbGciOiJFUzI1NiIsInR5cCI6IkpXVCJ9'
    '.'
    '.fakesig';

/// A JWT whose `client_id_scheme` is `x509_san_dns` instead of `did`.
const jwtWithWrongClientIdScheme =
    'eyJhbGciOiJFUzI1NiIsInR5cCI6IkpXVCJ9'
    '.'
    '.fakesig';

/// A JWT whose `client_id` is an empty string.
const jwtWithEmptyClientId =
    'eyJhbGciOiJFUzI1NiIsInR5cCI6IkpXVCJ9'
    '.'
    '.fakesig';
